	changed := ml.Alive("n2", 5, nil)
	if !changed {
		t.Fatal("higher incarnation should update")
	}
	m := ml.Get("n2")
	if m.Incarnation != 5 {
		t.Fatalf("expected incarnation 5, got %d", m.Incarnation)
	}
}

func TestMemberList_AliveLowerIncarnationIgnored(t *testing.T) {
	ml := NewMemberList("n1")
	ml.Alive("n2", 5, nil)
