+package membership
+
+import (
+	"testing"
+	"time"
+)
+
+func TestDefaultScalingValues(t *testing.T) {
+	defaultSWIM := DefaultSWIMConfig()
+	scaling := DefaultScaling()
+
+	if scaling.BaseProtocolPeriod != defaultSWIM.ProbeInterval {
+		t.Fatalf("base protocol period = %s, want %s", scaling.BaseProtocolPeriod, defaultSWIM.ProbeInterval)
+	}
+	if scaling.ProtocolPeriodStep != 250*time.Millisecond {
+		t.Fatalf("protocol period step = %s, want %s", scaling.ProtocolPeriodStep, 250*time.Millisecond)
+	}
+	if scaling.MaxProtocolPeriod != 10*time.Second {
+		t.Fatalf("max protocol period = %s, want %s", scaling.MaxProtocolPeriod, 10*time.Second)
+	}
+	if scaling.BaseProbeTimeout != defaultSWIM.ProbeTimeout {
+		t.Fatalf("base probe timeout = %s, want %s", scaling.BaseProbeTimeout, defaultSWIM.ProbeTimeout)
+	}
+	if scaling.BaseSuspicionTimeout != defaultSWIM.SuspicionTimeout {
+		t.Fatalf("base suspicion timeout = %s, want %s", scaling.BaseSuspicionTimeout, defaultSWIM.SuspicionTimeout)
+	}
+	if scaling.BaseIndirectChecks != defaultSWIM.IndirectChecks {
+		t.Fatalf("base indirect checks = %d, want %d", scaling.BaseIndirectChecks, defaultSWIM.IndirectChecks)
+	}
+
+	cfg := scaling.SWIMConfig(1)
+	if cfg.ProbeInterval != defaultSWIM.ProbeInterval {
+		t.Fatalf("single-node probe interval = %s, want %s", cfg.ProbeInterval, defaultSWIM.ProbeInterval)
+	}
+	if cfg.ProbeTimeout != defaultSWIM.ProbeTimeout {
+		t.Fatalf("single-node probe timeout = %s, want %s", cfg.ProbeTimeout, defaultSWIM.ProbeTimeout)
+	}
+	if cfg.IndirectChecks != defaultSWIM.IndirectChecks {
+		t.Fatalf("single-node indirect checks = %d, want %d", cfg.IndirectChecks, defaultSWIM.IndirectChecks)
+	}
+	if cfg.SuspicionTimeout != defaultSWIM.SuspicionTimeout {
+		t.Fatalf("single-node suspicion timeout = %s, want %s", cfg.SuspicionTimeout, defaultSWIM.SuspicionTimeout)
+	}
+}
+
+func TestScalingProtocolPeriodMonotonic(t *testing.T) {
+	scaling := DefaultScaling()
+	previous := scaling.ProtocolPeriod(0)
+
+	for size := 1; size <= 4096; size++ {
+		current := scaling.ProtocolPeriod(size)
+		if current < previous {
+			t.Fatalf("period decreased at size %d: %s < %s", size, current, previous)
+		}
+		previous = current
+	}
+}
+
+func TestScalingLog2Boundaries(t *testing.T) {
+	scaling := DefaultScaling()
+	base := scaling.BaseProtocolPeriod
+	step := scaling.ProtocolPeriodStep
+
+	tests := []struct {
+		size int
+		want time.Duration
+	}{
+		{0, base},
+		{1, base},
+		{2, base + step},
+		{3, base + 2*step},
+		{4, base + 2*step},
+		{5, base + 3*step},
+		{8, base + 3*step},
+		{16, base + 4*step},
+		{1 << 30, base + 30*step},
+	}
+
+	for _, tc := range tests {
+		got := scaling.ProtocolPeriod(tc.size)
+		if got != tc.want {
+			t.Fatalf("ProtocolPeriod(%d) = %s, want %s", tc.size, got, tc.want)
+		}
+	}
+}
+
+func TestScalingSWIMConfigUsesAllScaledValues(t *testing.T) {
+	scaling := DefaultScaling()
+	cfg := scaling.SWIMConfig(16)
+
+	if cfg.ProbeInterval != scaling.ProtocolPeriod(16) {
+		t.Fatalf("probe interval = %s, want %s", cfg.ProbeInterval, scaling.ProtocolPeriod(16))
+	}
+	if cfg.ProbeTimeout != scaling.ProbeTimeout(16) {
+		t.Fatalf("probe timeout = %s, want %s", cfg.ProbeTimeout, scaling.ProbeTimeout(16))
+	}
+	if cfg.IndirectChecks != scaling.IndirectChecks(16) {
+		t.Fatalf("indirect checks = %d, want %d", cfg.IndirectChecks, scaling.IndirectChecks(16))
+	}
+	if cfg.SuspicionTimeout != scaling.SuspicionTimeout(16) {
+		t.Fatalf("suspicion timeout = %s, want %s", cfg.SuspicionTimeout, scaling.SuspicionTimeout(16))
+	}
+}
+
+func TestScalingFanoutCapsAtDefaultMaximum(t *testing.T) {
+	scaling := DefaultScaling()
+
+	got := scaling.IndirectChecks(1 << 30)
+	if got != scaling.MaxIndirectChecks {
+		t.Fatalf("large-cluster indirect checks = %d, want cap %d", got, scaling.MaxIndirectChecks)
+	}
+}
+
+func TestScalingHandlesInvalidInputsMonotonically(t *testing.T) {
+	scaling := ScaledConfig{
+		BaseProtocolPeriod: -time.Second,
+		ProtocolPeriodStep: -time.Second,
+		BaseIndirectChecks: -3,
+		IndirectChecksStep: -1,
+	}
+
+	if got := scaling.ProtocolPeriod(0); got != 0 {
+		t.Fatalf("ProtocolPeriod(0) with negative config = %s, want 0", got)
+	}
+	if got := scaling.ProtocolPeriod(1024); got != 0 {
+		t.Fatalf("ProtocolPeriod(1024) with negative config = %s, want 0", got)
+	}
+	if got := scaling.IndirectChecks(1024); got != 0 {
+		t.Fatalf("IndirectChecks(1024) with negative config = %d, want 0", got)
+	}
+}
+
+func TestClusterSizeEstimatorZeroValueAndRepeatedNodes(t *testing.T) {
+	var estimator ClusterSizeEstimator
+
+	if got := estimator.Estimate(); got != 0 {
+		t.Fatalf("zero-value estimate = %d, want 0", got)
+	}
+	if got := estimator.Observe("n1"); got != 1 {
+		t.Fatalf("after n1 estimate = %d, want 1", got)
+	}
+	if got := estimator.Observe("n1"); got != 1 {
+		t.Fatalf("after repeated n1 estimate = %d, want 1", got)
+	}
+	if got := estimator.Observe("n2"); got != 2 {
+		t.Fatalf("after n2 estimate = %d, want 2", got)
+	}
+	if got := estimator.ObserveMany("n2", "n3", "n4", "n3"); got != 4 {
+		t.Fatalf("after repeated batch estimate = %d, want 4", got)
+	}
+	if got := estimator.Estimate(); got != 4 {
+		t.Fatalf("final estimate = %d, want 4", got)
+	}
+}
+
+func TestClusterSizeEstimatorConstructorAndReset(t *testing.T) {
+	estimator := NewClusterSizeEstimator("n1", "n2", "n2")
+
+	if got := estimator.Estimate(); got != 2 {
+		t.Fatalf("seeded estimate = %d, want 2", got)
+	}
+	estimator.Reset()
+	if got := estimator.Estimate(); got != 0 {
+		t.Fatalf("estimate after reset = %d, want 0", got)
+	}
+	if got := estimator.Observe("n3"); got != 1 {
+		t.Fatalf("estimate after reset and observe = %d, want 1", got)
+	}
+}
