// ScaledConfig scales SWIM timing and fanout parameters by cluster size.
//
// The scale level is ceil(log2(clusterSize)), with zero and single-node
// clusters treated as level 0. This keeps small clusters responsive while
// increasing the protocol period as clusters grow.
type ScaledConfig struct {
	// BaseProtocolPeriod is the protocol period for a zero or single-node cluster.
	BaseProtocolPeriod time.Duration
	// ProtocolPeriodStep is added once per log2 scale level.
	ProtocolPeriodStep time.Duration
	// MaxProtocolPeriod caps the protocol period when greater than zero.
	MaxProtocolPeriod time.Duration

	// BaseProbeTimeout is the direct probe timeout for a zero or single-node cluster.
	BaseProbeTimeout time.Duration
	// ProbeTimeoutStep is added once per log2 scale level.
	ProbeTimeoutStep time.Duration
	// MaxProbeTimeout caps the probe timeout when greater than zero.
	MaxProbeTimeout time.Duration

	// BaseSuspicionTimeout is the suspicion timeout for a zero or single-node cluster.
	BaseSuspicionTimeout time.Duration
	// SuspicionTimeoutStep is added once per log2 scale level.
	SuspicionTimeoutStep time.Duration
	// MaxSuspicionTimeout caps the suspicion timeout when greater than zero.
	MaxSuspicionTimeout time.Duration

	// BaseIndirectChecks is the indirect probe fanout for a zero or single-node cluster.
	BaseIndirectChecks int
	// IndirectChecksStep is added once per log2 scale level.
	IndirectChecksStep int
	// MaxIndirectChecks caps indirect checks when greater than zero.
	MaxIndirectChecks int
}

// DefaultScaling returns log2-based SWIM scaling defaults.
func DefaultScaling() ScaledConfig {
	cfg := DefaultSWIMConfig()
	return ScaledConfig{
		BaseProtocolPeriod:   cfg.ProbeInterval,
		ProtocolPeriodStep:   250 * time.Millisecond,
		MaxProtocolPeriod:    10 * time.Second,
		BaseProbeTimeout:     cfg.ProbeTimeout,
		ProbeTimeoutStep:     50 * time.Millisecond,
		MaxProbeTimeout:      2 * time.Second,
		BaseSuspicionTimeout: cfg.SuspicionTimeout,
		SuspicionTimeoutStep: time.Second,
		MaxSuspicionTimeout:  time.Minute,
		BaseIndirectChecks:   cfg.IndirectChecks,
		IndirectChecksStep:   1,
		MaxIndirectChecks:    12,
	}
}

// ProtocolPeriod returns the scaled SWIM protocol period for clusterSize.
func (c ScaledConfig) ProtocolPeriod(clusterSize int) time.Duration {
	return scaledDuration(c.BaseProtocolPeriod, c.ProtocolPeriodStep, scaleLevel(clusterSize), c.MaxProtocolPeriod)
}

// ProbeTimeout returns the scaled direct probe timeout for clusterSize.
func (c ScaledConfig) ProbeTimeout(clusterSize int) time.Duration {
	return scaledDuration(c.BaseProbeTimeout, c.ProbeTimeoutStep, scaleLevel(clusterSize), c.MaxProbeTimeout)
}

// SuspicionTimeout returns the scaled suspect-to-dead timeout for clusterSize.
func (c ScaledConfig) SuspicionTimeout(clusterSize int) time.Duration {
	return scaledDuration(c.BaseSuspicionTimeout, c.SuspicionTimeoutStep, scaleLevel(clusterSize), c.MaxSuspicionTimeout)
}

// IndirectChecks returns the scaled indirect probe fanout for clusterSize.
func (c ScaledConfig) IndirectChecks(clusterSize int) int {
	return scaledInt(c.BaseIndirectChecks, c.IndirectChecksStep, scaleLevel(clusterSize), c.MaxIndirectChecks)
}

// SWIMConfig returns a SWIMConfig populated with values scaled for clusterSize.
func (c ScaledConfig) SWIMConfig(clusterSize int) SWIMConfig {
	return SWIMConfig{
		ProbeInterval:    c.ProtocolPeriod(clusterSize),
		ProbeTimeout:     c.ProbeTimeout(clusterSize),
		IndirectChecks:   c.IndirectChecks(clusterSize),
		SuspicionTimeout: c.SuspicionTimeout(clusterSize),
	}
}

// ClusterSizeEstimator tracks observed node IDs and reports the current estimate.
//
// The zero value is ready to use. Repeated observations of the same node do not
// increase the estimate.
type ClusterSizeEstimator struct {
	mu    sync.RWMutex
	nodes map[string]struct{}
}

// NewClusterSizeEstimator creates an estimator, optionally seeded with node IDs.
func NewClusterSizeEstimator(ids ...string) *ClusterSizeEstimator {
	e := &ClusterSizeEstimator{}
	e.ObserveMany(ids...)
	return e
}

// Observe records a node ID and returns the current size estimate.
func (e *ClusterSizeEstimator) Observe(id string) int {
	e.mu.Lock()
	defer e.mu.Unlock()
	e.initLocked()
	e.nodes[id] = struct{}{}
	return len(e.nodes)
}

// ObserveMany records node IDs and returns the current size estimate.
func (e *ClusterSizeEstimator) ObserveMany(ids ...string) int {
	e.mu.Lock()
	defer e.mu.Unlock()
	e.initLocked()
	for _, id := range ids {
		e.nodes[id] = struct{}{}
	}
	return len(e.nodes)
}

// Estimate returns the current size estimate.
func (e *ClusterSizeEstimator) Estimate() int {
	e.mu.RLock()
	defer e.mu.RUnlock()
	return len(e.nodes)
}

// Reset clears all observations.
func (e *ClusterSizeEstimator) Reset() {
	e.mu.Lock()
	defer e.mu.Unlock()
	e.nodes = nil
}

func (e *ClusterSizeEstimator) initLocked() {
	if e.nodes == nil {
		e.nodes = make(map[string]struct{})
	}
}

func scaleLevel(clusterSize int) int {
	if clusterSize <= 1 {
		return 0
	}
	return bits.Len(uint(clusterSize - 1))
}

func scaledDuration(base, step time.Duration, level int, max time.Duration) time.Duration {
	if base < 0 {
		base = 0
	}
	if step < 0 {
		step = 0
	}
	if max > 0 && max < base {
		base = max
	}
	if level <= 0 || step == 0 {
		return base
	}

	value := base
	for i := 0; i < level; i++ {
		next := value + step
		if next < value {
			if max > 0 {
				return max
			}
			return time.Duration(1<<63 - 1)
		}
		value = next
		if max > 0 && value >= max {
			return max
		}
	}
	return value
}

func scaledInt(base, step, level, max int) int {
	if base < 0 {
		base = 0
	}
	if step < 0 {
		step = 0
	}
	if max > 0 && max < base {
		base = max
	}
	if level <= 0 || step == 0 {
		return base
	}

	value := base
	maxInt := int(^uint(0) >> 1)
	for i := 0; i < level; i++ {
		if step > maxInt-value {
			if max > 0 {
				return max
			}
			return maxInt
		}
		value += step
		if max > 0 && value >= max {
			return max
		}
	}
	return value
}

